void OnTimer(void)

{

        //Add your command handler code here

   SetTimer(0);

   canNotClick=0;

}



void OnLButtonDown(int x,int y)

{

        //Add your command handler code here

   Sound_Holder.Stop(2);

   SetTimer(0);

}



void OnRButtonDown(int x,int y)

{

        //Add your command handler code here

   Sound_Holder.PlayDSound(2);

}



void Video_Holder.TheEnd(int videoID)

{

   Video_Holder.Stop();

   Sound_Holder.PlayDSound(1);

   SetCursor(0);

}





void Video_Holder.MouseClickOn(int videoID)

{

   if(canNotClick)   return;

   Video_Holder.Stop();

   Sound_Holder.PlayDSound(1);

   SetCursor(0);

}





void Transparent_Video_Holder.TheEnd(int videoID)

{

   int xx=0;

   while(xx<11)

   {

      if(videos[xx]==0)   break;

      xx++;

   }

   if(xx==11)

   {

      xx=0;

      while(xx<11)

      {

         videos[xx]=0;

         xx++;

      }

      SetCursor(-3);

      canNotClick=1;

      SetTimer(6000);

      Sound_Holder.StopAll();

      Video_Holder.Stop();

//      Video_Holder.PlayFromTo(0,0,4716);

      Video_Holder.Play(0);

   }

}
